CREATE OR REPLACE FUNCTION fpa_tel_book_confirm_lon (as_memno char,adt_date timestamp(0),as_loan_type char,as_type char) RETURNS bigint AS $body$
DECLARE

  ldc_amount bigint;

BEGIN
  if as_type = 'SUM' then
    select sum(pka_com_function.fp_lon_get_balance_atdate(sc_lon_m_loan_card.loan_contract_no,adt_date))
    into STRICT  ldc_amount
    from  sc_lon_m_loan_card
        , sc_lon_m_rule
    where (sc_lon_m_loan_card.loan_type = sc_lon_m_rule.loan_type)
    and (sc_lon_m_rule.loan_group_code = as_loan_type)
    and (sc_lon_m_loan_card.membership_no = as_memno);
  else
    select count(loan_contract_no)
    into STRICT  ldc_amount
    from  sc_lon_m_loan_card
        , sc_lon_m_rule
    where (sc_lon_m_loan_card.loan_type = sc_lon_m_rule.loan_type)
    and (sc_lon_m_rule.loan_group_code = as_loan_type)
    and (sc_lon_m_loan_card.membership_no = as_memno)
    and (pka_com_function.fp_lon_get_balance_atdate(sc_lon_m_loan_card.loan_contract_no,adt_date)) > 0;
  end if;

  return coalesce(ldc_amount,0);
exception
when no_data_found  then return 0;
when others then CALL spa_dberror('FPA_TEL_BOOK_CONFIRM_LON');
END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
